    // downstream full?
    fsm_fire = in_valid && ( ! skid_valid);
    // input_will_be_free = (~in_valid) || (in_valid && ~skid_full);
    // % * ~in_valid               -> буфер пуст
    // % * in_valid && ~skid_full  -> FSM точно съест данные в этом такте
    // 
