    //     in_valid = true;
    // elseif fsm_fire
    //     in_valid = false;
    // end
    rx_err_r_next = 1'b0;
    t_0 = lane_up && channel_up;
    if ( ! t_0) begin
      flow_ctrl_state_temp = 3'b000;
      tx_state_reg_temp = 2'b00;
      rx_state_reg_temp = 2'b00;
