    if (s_axi_rx_snf) begin
      NFC_rcvd_value_reg_next = s_axi_rx_fc_nb;
    end
    case ( rx_state_reg_temp)
      2'b00 :
        begin
          if (s_axi_tvalid) begin
            rx_previous_reg_next = s_axi_tdata;
            rx_state_reg_temp = 2'b01;
          end
          else begin
            rx_state_reg_temp = 2'b00;
          end
        end
      default :
        begin
          if (s_axi_tvalid) begin
            if (s_axi_tdata != (rx_previous_reg + 32'b00000000000000000000000000000001)) begin
              rx_err_r_next = 1'b1;
            end
            rx_previous_reg_next = s_axi_tdata;
          end
        end
    endcase
    case ( flow_ctrl_state_temp)
      3'b000 :
        begin
          if (lane_up && channel_up) begin
            flow_ctrl_state_temp = 3'b001;
          end
          else begin
            flow_ctrl_state_temp = 3'b000;
          end
        end
      3'b001 :
        begin
          if (LinkPartner_XOFF) begin
            // DISABLE Link Partner
            axi_nfc_req_tmp_next = 1'b1;
            // axi_nfc_nb_reg = fi(dbg_NFC_NB_in,0,axi_nfc_nb_reg.WordLength,0,fm);
            axi_nfc_nb_reg_next = 4'b1111;
            flow_ctrl_state_temp = 3'b010;
            // else
            //     flow_ctrl_state(1) = flow_ctrl_state(1);
          end
        end
      3'b010 :
        begin
          if (m_axi_nfc_ack) begin
            axi_nfc_req_tmp_next = 1'b0;
            flow_ctrl_state_temp = 3'b011;
          end
        end
      3'b011 :
        begin
          if ( ! LinkPartner_XOFF) begin
            // ENABLE Link Partner
            axi_nfc_req_tmp_next = 1'b1;
            // axi_nfc_nb_reg = fi(dbg_NFC_NB_in,0,axi_nfc_nb_reg.WordLength,0,fm);
            axi_nfc_nb_reg_next = 4'b0000;
            flow_ctrl_state_temp = 3'b100;
            // else
            //     flow_ctrl_state(1) = flow_ctrl_state(1);
          end
        end
      default :
        begin
          if (m_axi_nfc_ack) begin
            axi_nfc_req_tmp_next = 1'b0;
            flow_ctrl_state_temp = 3'b000;
          end
        end
    endcase
    // ================= FSM =================
    // FIFO → INPUT BUFFER → FSM → OUTPUT SKID → AXIS
    out_valid = 1'b0;
    out_last = 1'b0;
    out_data = 32'b00000000000000000000000000000000;
    input_hold = 1'b0;
    // fsm_fire = in_valid && ~skid_full;
    case ( tx_state_reg_temp)
      2'b00 :
        begin
          if (lane_up && channel_up) begin
            tx_state_reg_temp = 2'b01;
          end
          else begin
            tx_state_reg_temp = 2'b00;
          end
        end
      2'b01 :
        begin
          // if in_valid && ~skid_full
          if (fsm_fire) begin
            out_data = in_data;
            out_valid = 1'b1;
            // consume ТОЛЬКО здесь
            in_valid_temp = 1'b0;
            if (beat_cnt == (N1 - 8'b00000001)) begin
              tx_state_reg_temp = 2'b10;
              beat_cnt_next = 8'b00000000;
            end
            else begin
              beat_cnt_next = beat_cnt + 8'b00000001;
            end
          end
        end
      default :
        begin
          // send last (D_WORD_rd_data)
          // if (axis_ready_int)
          if ( ! skid_valid) begin
            out_data = {16'b0, D_WORD_rd_data};
            out_valid = 1'b1;
            out_last = 1'b1;
            tx_state_reg_temp = 2'b01;
          end
          input_hold = 1'b1;
        end
    endcase
    // ================= OUTPUT SKID =================
    // вход от FSM
    // ================= NEXT STATE LOGIC =================
    m_axis_tvalid_reg_next = m_axis_tvalid_reg;
    m_axis_tdata_reg_next = m_axis_tdata_reg;
    m_axis_tlast_reg_next = m_axis_tlast_reg;
    skid_valid_next = skid_valid;
    // ================= POP =================
    can_pop = m_axis_tvalid_reg && m_axi_tready;
    if (can_pop) begin
      if (skid_valid) begin
        m_axis_tdata_reg_next = skid_data;
        m_axis_tlast_reg_next = skid_last;
        m_axis_tvalid_reg_next = 1'b1;
        skid_valid_next = 1'b0;
      end
      else begin
        m_axis_tdata_reg_next = out_data;
        m_axis_tlast_reg_next = out_last;
        m_axis_tvalid_reg_next = out_valid;
      end
    end
    else if ( ! m_axis_tvalid_reg) begin
      // ===== BOOTSTRAP (SAFE) =====
      if (skid_valid) begin
        m_axis_tdata_reg_next = skid_data;
        m_axis_tlast_reg_next = skid_last;
        m_axis_tvalid_reg_next = 1'b1;
        skid_valid_next = 1'b0;
      end
      else if (out_valid) begin
        m_axis_tdata_reg_next = out_data;
        m_axis_tlast_reg_next = out_last;
        m_axis_tvalid_reg_next = 1'b1;
      end
    end
    // ================= PUSH =================
    if (out_valid) begin
      // ONLY BACKPRESSURE PATH
      if (m_axis_tvalid_reg && ( ! can_pop)) begin
        // output занят → backlog в skid
        skid_data_next = out_data;
        skid_last_next = out_last;
        skid_valid_next = 1'b1;
      end
      else if ((m_axis_tvalid_reg && can_pop) && skid_valid) begin
        // pop+push case → skid extension
        skid_data_next = out_data;
        skid_last_next = out_last;
        skid_valid_next = 1'b1;
        // elseif ~m_valid
        //     % ❌ ВАЖНО: убрали direct m write
        //     % ничего не делаем тут
        //     % (m заполняется ТОЛЬКО POP)
      end
    end
    input_will_be_free = ( ! in_valid_temp) || (in_valid_temp && ( ! skid_valid));
    // input_will_be_free = (~in_valid) || (in_valid && ~skid_valid);
    // * ~in_valid               -> буфер пуст
    // * in_valid && ~skid_full  -> FSM точно съест данные в этом такте
    // D_FIFO_rd_en = (~D_FIFO_rd_empty) && input_will_be_free;
    D_FIFO_rd_en1 = (( ! D_FIFO_rd_empty) && ( ! input_hold)) && input_will_be_free;
    // ================= INPUT BUFFER UPDATE =================
    if (D_FIFO_rd_en1) begin
      in_data_next = D_FIFO_rd_data;
      in_valid_temp = 1'b1;
    end
    m_axis_tdata = m_axis_tdata_reg;
    m_axis_tvalid = m_axis_tvalid_reg;
    m_axis_tlast = m_axis_tlast_reg;
    m_axis_tkeep = 4'b0000;
    m_axis_tuser = 1'b0;
    state = tx_state_reg;
    m_axi_nfc_req_1 = axi_nfc_req_tmp;
    m_axi_nfc_nb_1 = axi_nfc_nb_reg;
    NFC_rcvd_value = NFC_rcvd_value_reg;
    rx_err = rx_err_r;
    D_FIFO_rd_en_1 = D_FIFO_rd_en1;
    D_WORD_rd_en_1 = 1'b0;
    tx_state_reg_next = tx_state_reg_temp;
    rx_state_reg_next = rx_state_reg_temp;
    flow_ctrl_state_next = flow_ctrl_state_temp;
    in_valid_next = in_valid_temp;
  end



